import { Navigate, Route, Routes } from 'react-router-dom';
import AdminDashboardPage from '../pages/AdminDashboardPage.jsx';
import MentorDashboardPage from '../pages/MentorDashboardPage.jsx';
import ReportsAnalyticsPage from '../pages/ReportsAnalyticsPage.jsx';
import ReviewQueuePage from '../pages/ReviewQueuePage.jsx';
import ReviewSubmissionPage from '../pages/ReviewSubmissionPage.jsx';
import UserManagementPage from '../pages/UserManagementPage.jsx';

export const adminMentorRouteConfig = {
  adminBasePath: '/admin/*',
  mentorBasePath: '/mentor/*',
  adminDefaultPath: '/admin',
  mentorDefaultPath: '/mentor',
};

export default function AdminMentorRoutes({ area }) {
  /*
   * ROUTER RIENG CHO MODULE MEMBER 5.
   * Khi merge vao App.js tong cua nhom, chi can import component nay va boc bang ProtectedRoute:
   * <Route path="/admin/*" element={<ProtectedRoute allowedRoles={['ADMIN']}><AdminMentorRoutes area="admin" /></ProtectedRoute>} />
   * <Route path="/mentor/*" element={<ProtectedRoute allowedRoles={['MENTOR']}><AdminMentorRoutes area="mentor" /></ProtectedRoute>} />
   */
  if (area === 'mentor') {
    return (
      <Routes>
        <Route element={<MentorDashboardPage />} path="/mentor" />
        <Route element={<ReviewQueuePage />} path="/mentor/review-queue" />
        <Route element={<ReviewSubmissionPage />} path="/mentor/reviews/:submissionId" />
        <Route element={<ReviewSubmissionPage />} path="/mentor/submissions/:submissionId/review" />
        <Route element={<Navigate replace to="/mentor" />} path="*" />
      </Routes>
    );
  }

  return (
    <Routes>
      <Route element={<AdminDashboardPage />} path="/admin" />
      <Route element={<UserManagementPage />} path="/admin/users" />
      <Route element={<ReportsAnalyticsPage />} path="/admin/reports" />
      <Route element={<Navigate replace to="/admin" />} path="*" />
    </Routes>
  );
}
